typedef struct {

  // MMIO
  volatile unsigned int *mmio;
  // ADDR - defined for each motor in rover.h
  off_t addr;

  // GPIO Output Control Signals
  uint8_t duty_cycle;  // 8 bits
  uint8_t clk_divisor; // 3 bits
  uint8_t dir;         // 1 bit
  uint8_t en_motor;    // 1 bit
  uint8_t clear_enc;   // 1 bit
  uint8_t en_enc;      // 1 bit

  // GPIO Input Control Signals
  int16_t counts; // 16 bits

} MotorController;

int MotorController_init(MotorController *motor, off_t mmio_address);
void MotorController_close(MotorController *motor);

void MotorController_write(MotorController *motor);
void MotorController_read(MotorController *motor);

#endif

#include <aio.h>

#include "mmio.h"
#include "motor.h"

int MotorController_init(MotorController *motor, off_t mmio_address) {
  // Initialize MMIO
  volatile unsigned int *mmio = mmio_init(mmio_address);

  if (!mmio_is_valid(mmio))
    return -1;

  // Initialize motor controller
  motor->mmio = mmio;
  motor->addr = mmio_address;
  motor->duty_cycle = 0;
  motor->clk_divisor = 2;
  motor->dir = 1;
  motor->en_motor = 1;
  motor->clear_enc = 1;
  motor->en_enc = 1;

  // Clear encoder counter
  MotorController_write(motor);
  motor->clear_enc = 0;
  MotorController_write(motor);

  return 0;
}

void MotorController_close(MotorController *motor) {
  // Disable motor controller
  motor->en_motor = 0;
  motor->en_enc = 0;
  MotorController_write(motor);

  // Release MMIO
  close_mem(motor->mmio);
}

void MotorController_write(MotorController *motor) {
  // Write to MMIO
  *(motor->mmio) = motor->duty_cycle + (motor->clk_divisor << 8) +
                   (motor->dir << 11) + (motor->en_motor << 12) +
                   (motor->clear_enc << 13) + (motor->en_enc << 14);
}

void MotorController_read(MotorController *motor) {
  // Read MMIO
  motor->counts = *(motor->mmio + 2);
}

